-- Certa DB 스키마
-- 실행 방법: Supabase 대시보드 > SQL Editor 에 이 파일 내용을 붙여넣고 실행하세요.
-- (anon/service_role key로는 REST API를 통한 DDL 실행이 불가능해서, 최초 1회는
--  대시보드 SQL Editor에서 직접 실행해야 합니다.)

create extension if not exists "pgcrypto";

-- 1. 자격증 정보 테이블
create table if not exists certifications (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  category text not null,
  issuing_org text not null,
  exam_fee integer not null default 0,
  prep_weeks integer not null default 0,
  pass_rate numeric(5,2) not null default 0,
  difficulty smallint not null default 3 check (difficulty between 1 and 5),
  target_job text[] not null default '{}',
  description text,
  verified boolean not null default false,
  created_at timestamptz not null default now()
);

-- 2. 커뮤니티 게시글
create table if not exists community_posts (
  id uuid primary key default gen_random_uuid(),
  cert_id uuid references certifications(id) on delete set null,
  author_name text not null default '익명',
  title text not null,
  content text not null,
  post_type text not null default 'general' check (post_type in ('general','study_group','question')),
  created_at timestamptz not null default now()
);

-- 3. 커뮤니티 댓글
create table if not exists community_comments (
  id uuid primary key default gen_random_uuid(),
  post_id uuid not null references community_posts(id) on delete cascade,
  author_name text not null default '익명',
  content text not null,
  created_at timestamptz not null default now()
);

-- 4. 문제 (연습문제 - 실제 기출문제 아님. 자세한 내용은 README 참고)
create table if not exists quiz_questions (
  id uuid primary key default gen_random_uuid(),
  cert_id uuid not null references certifications(id) on delete cascade,
  question text not null,
  choices jsonb not null,
  answer_index smallint not null,
  explanation text,
  year integer,
  created_at timestamptz not null default now()
);

-- 이미 예전 버전의 schema.sql을 실행한 적이 있어도 안전하게 재실행할 수 있도록
-- 컬럼/제약조건을 보강합니다.
alter table certifications add column if not exists verified boolean not null default false;

do $$
begin
  alter table certifications add constraint certifications_name_key unique (name);
exception
  when duplicate_table then null;
  when duplicate_object then null;
end $$;

-- ===== RLS (Row Level Security) =====
alter table certifications enable row level security;
alter table community_posts enable row level security;
alter table community_comments enable row level security;
alter table quiz_questions enable row level security;

drop policy if exists "certifications_public_read" on certifications;
create policy "certifications_public_read" on certifications
  for select using (true);

drop policy if exists "quiz_questions_public_read" on quiz_questions;
create policy "quiz_questions_public_read" on quiz_questions
  for select using (true);

drop policy if exists "community_posts_public_read" on community_posts;
create policy "community_posts_public_read" on community_posts
  for select using (true);
drop policy if exists "community_posts_public_insert" on community_posts;
create policy "community_posts_public_insert" on community_posts
  for insert with check (true);

drop policy if exists "community_comments_public_read" on community_comments;
create policy "community_comments_public_read" on community_comments
  for select using (true);
drop policy if exists "community_comments_public_insert" on community_comments;
create policy "community_comments_public_insert" on community_comments
  for insert with check (true);

-- ===== 자격증 카탈로그 (108개) =====
-- verified = true: 응시료·합격률 등을 실제 검색으로 확인한 자격증 (8개)
-- verified = false: 이름·분류·주관기관은 실존하지만, 응시료/합격률 수치는
--                     아직 확인하지 못한 자격증 (숫자를 지어내지 않고 "확인 중"으로 표시)
-- 총 108개 자격증
on conflict (name) do nothing;

